import{_ as a,o,c as s,a3 as t}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"57. Compassionate Leave","description":"","frontmatter":{"title":"57. Compassionate Leave","eba":"Biomedical Engineers 2025-2028","topics":["leave","compassionate-leave"]},"headers":[],"relativePath":"ebas/biomedical-engineers/leave/57-compassionate-leave.md","filePath":"ebas/biomedical-engineers/leave/57-compassionate-leave.md"}'),n={name:"ebas/biomedical-engineers/leave/57-compassionate-leave.md"};function i(r,e,p,l,m,c){return o(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="_57-compassionate-leave" tabindex="-1">57. Compassionate Leave <a class="header-anchor" href="#_57-compassionate-leave" aria-label="Permalink to &quot;57. Compassionate Leave&quot;">​</a></h1><p><strong>57.1</strong> When Compassionate Leave is Available</p><p><strong>(a)</strong> Compassionate leave may be available to an Employee under this clause 57:</p><p><strong>(i)</strong> if a member of the Employee’s Immediate Family or household: <strong>(A)</strong> contracts or develops a personal illness or sustains a personal injury that poses a serious threat to their life; <strong>(B)</strong> dies;</p><p><strong>(ii)</strong> when a child is Stillborn, where the child would have been a member of the Employee’s Immediate Family, or household member, if the child had been born alive; or</p><p><strong>(iii)</strong> the Employee, or the Employee’s spouse or de facto partner has a miscarriage. (a permissible occasion)</p><p><strong>(b)</strong> If the permissible occasion is the contraction or development of a personal illness, or the sustaining of a personal injury, the Employee may take the compassionate leave for that occasion at any time while the illness or injury persists.</p><p><strong>57.2</strong> Employees Other than Casual Employees</p><p><strong>(a)</strong> An Employee is entitled to up to two (2) ordinary days’ paid leave, on each permissible occasion.</p><p><strong>(b)</strong> An Employee may take compassionate leave for a particular permissible occasion as:</p><p><strong>(i)</strong> a single continuous two (2) day period;</p><p><strong>(ii)</strong> two (2) separate periods of one (1) day each; or</p><p><strong>(iii)</strong> any separate periods to which the Employee and Employer agree.</p><p><strong>(c)</strong> An Employee may take unpaid additional compassionate leave by agreement with the Employer.</p><p><strong>57.3</strong> Casual Employees Subject to the evidence requirements described at subclause 57.4, a casual Employee is entitled to two (2) days unpaid compassionate leave on each permissible occasion. Unpaid compassionate leave under this clause may be taken as:</p><p><strong>(a)</strong> a single continuous period,</p><p><strong>(b)</strong> two (2) separate periods of one (1) day each, or</p><p><strong>(c)</strong> any separate periods to which the Employee and Employer agree.</p><p><strong>57.4</strong> Evidence – All Employees Proof of the permissible occasion must be provided that would satisfy a reasonable person, if requested.</p><p>Plain language terms: bereavement leave.</p>',20)])])}const g=a(n,[["render",i]]);export{h as __pageData,g as default};
